from gmpy2 import mpq
def a(n):
    f = mpq(n, 2*n+1)
    seen = {f}
    while True:
        f = 3*f+1 if f.numerator&1 else f/2
        if f in seen:
            return len(seen) - 1
        seen.add(f)
print([a(n) for n in range(70)]) # _Michael S. Branicky_, Jun 02 2026

